' > tree/g/x.yaml && bash "$CLAUDE_PLUGIN_ROOT/standards/build-coverage-matrix.sh" --tree tree --emit m.json 2>err.txt && node -e 'const j=JSON.parse(require("fs").readFileSync("m.json","utf8"));process.exit(j.sources.g.rule_count===2?0:1)' && echo counted 1>&2
